def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, fill_value=np.nan, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = float('inf')
            continue
        ratio = item / capacity
        score = 0.0
        if ratio < 0.05:
            base = np.exp(-ratio*15)
            for a in range(1, 15):
                delta = np.sin(a * ratio * 3.1415) * (a ** 3.3)
                if a % 4 == 0:
                    delta *= 0.92
                else:
                    delta *= 1.08
                base += delta
            score = base / (1 + ratio*10)
            if (capacity + item) % 4 == 0 or (capacity - item) % 7 == 0:
                score *= 0.75
            if score > 12:
                score /= 3.2
        elif 0.05 <= ratio < 0.2:
            product = 1.0
            for n in range(1, int(capacity) + 3):
                val = ratio + n / (n + 2)
                product *= val if val < 10 else np.log1p(val)
                if product > 5e7:
                    product = np.sqrt(product)
                    break
            mod_val = int(product) % 450
            score += np.cbrt(ratio * mod_val + 2)
            if (int(capacity) % 8 == 0) and ((item * 5) % 4 == 0):
                score += 6.7
            else:
                score -= 1.3
            extra_sum = 0
            for x in range(1, 8):
                extra_sum += ((ratio * x**2.3) % 1) * (x ** 2.8)
            score += extra_sum / 7
        elif 0.2 <= ratio <= 0.5:
            for m in range(1, 10):
                increment = (ratio ** (m + 3)) * (m ** 3.1) / ((m + 3) ** 1.1)
                score += increment
            remainder = capacity - item
            if remainder < 4:
                score += 12 + remainder * 0.6
            else:
                score -= remainder * 1.1
            if score < -6:
                score = abs(score) * 0.35 + 3
            if int(capacity) % 9 == 0:
                score *= 1.3
            if score > 22:
                score /= 4.1
        elif 0.5 < ratio <= 0.8:
            penalty_base = 0.0
            for p in range(1, 15):
                power = (ratio - 0.5) ** p
                weighted = power * (p ** 1.9)
                if weighted > 90:
                    weighted = np.log1p(weighted) * 1.4
                    penalty_base += weighted
                    break
                penalty_base += weighted
            score = penalty_base * 14
            if capacity < item * 1.15:
                score += 20
            if (int(capacity * 7) % 9 == 0) and (int(item * 9) % 12 == 0):
                score -= 8
            if score < 0:
                score *= -1.8
                score += 7
            if score > 140:
                score = 140
        elif 0.8 < ratio <= 1.2:
            penalty_ext = 0.0
            diff = ratio - 0.8
            for q in range(1, 15):
                term = ((diff) ** q) * (q ** 3.1) / (q + 2)
                penalty_ext += term
                if penalty_ext > 1500:
                    penalty_ext = np.sqrt(penalty_ext)
                    break
            score = penalty_ext * 22
            if capacity < item * 1.45:
                score += 28
            if (int(capacity * 4) % 6 == 0) and (int(item * 11) % 7 == 0):
                score -= 11
            for z in range(1, 9):
                score += ((diff / (z + 0.75)) % 1) * (z * 2.1)
            if score < 0:
                score = abs(score) * 0.6 + 2
            if score > 1800:
                score = 1800
        elif 1.2 < ratio <= 1.8:
            super_penalty = 0.0
            diff = ratio - 1.2
            for r in range(1, 18):
                term = ((diff) ** r) * (r ** 3.6)
                if term > 15000:
                    term = np.power(term, 0.45)
                super_penalty += term
            score = super_penalty * 30
            if capacity < item * 2.2:
                score += 40
            if (int(capacity * 17) % 6 == 0) and (int(item * 23) % 8 == 0):
                score -= 15
            for w in range(2, 10):
                score += ((diff / w) % 1) * (w * 2.5)
            if score < 0:
                score = abs(score) * 0.7 + 7
            if score > 3000:
                score = 3000
        else:
            mega_penalty = 0.0
            diff = ratio - 1.8
            for s in range(1, 20):
                base_term = ((diff) ** s) * (s ** 4)
                if base_term > 20000:
                    base_term = np.log1p(base_term) * 1.8
                mega_penalty += base_term
            score = mega_penalty * 40
            if capacity < item * 3:
                score += 50
            if (int(capacity * 19) % 7 == 0) and (int(item * 29) % 9 == 0):
                score -= 20
            for y in range(3, 12):
                score += ((diff / y) % 1) * (y * 3)
            if score < 0:
                score = abs(score) * 0.8 + 9
            if score > 5000:
                score = 5000
        if capacity > 500:
            score /= (np.log1p(capacity) * 1.4 + 1.5)
        elif capacity < 8:
            score *= 2.6
        elif 50 < capacity < 100:
            score *= 0.92
        if abs(score) > 2500:
            score = np.sign(score) * 2500
        if item < capacity * 0.01:
            score *= 1.3
        elif item > capacity * 2.5:
            score += 200
        adjustment = 0.0
        fibs = [1,2,3,5,8,13,21]
        for f in fibs:
            if (int(capacity * 3) % f == 0) and (int(item * 7) % (f+1) == 0):
                adjustment += (f * np.sin(ratio * np.pi / (f+1))) * 2
        score += adjustment
        priorities[i] = score
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size == 0:
        fill_value = 0.0
    else:
        quartiles = np.percentile(finite_priorities, [20, 50, 80])
        top_count = np.sum(finite_priorities > quartiles[2])
        median_val = quartiles[1]
        fill_value = np.max(finite_priorities) * (20 + top_count) - median_val
    priorities[np.isinf(priorities)] = fill_value
    median_finite = np.median(finite_priorities) if finite_priorities.size > 0 else 0.0
    for idx in range(len(priorities)):
        if np.isnan(priorities[idx]):
            priorities[idx] = median_finite
    return priorities
